// Store the tweet ID from the API response for the next iteration
const tweetId = $input.first().json.data.id;

// Save to workflow static data (persists across loop iterations)
$workflow.staticData.lastTweetId = tweetId;

// Return the data with the tweet ID
return [{
  json: {
    ...$input.first().json,
    storedTweetId: tweetId
  }
}];

// n8n Code node (JavaScript)

const k = 10;
const input = $input.all();

if (input.length === 0) {
  return [{ json: { items: [] } }];
}

// Shuffle (Fisher–Yates)
const arr = [...input];
for (let i = arr.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [arr[i], arr[j]] = [arr[j], arr[i]];
}

const selected = arr.slice(0, Math.min(k, arr.length));

// 1 seul item de sortie, avec une liste de 10 items (leurs json)
return [
  {
    json: {
      items: selected.map((it) => it.json),
      count: selected.length,
    },
  },
];

